function parseInjectionHeaders(headers) {
    const injectionPoints = {};
    
    // Only process headers that start with our custom prefix
    Object.entries(headers).forEach(([key, value]) => {
        if (key.toLowerCase().startsWith('x-inject-')) {
            const selector = key.substring(11); // Remove 'x-inject-' prefix
            const content = value[0]?.value || '';
            
            // Validate selector and content
            if (selector && content) {
                injectionPoints[selector] = content;
            }
        }
    });
    
    return injectionPoints;
}

function isValidSelector(selector) {
    // Allow only simple CSS selectors
    const allowedPatterns = [
        /^[a-zA-Z][a-zA-Z0-9_-]*$/, // Element names
        /^[a-zA-Z][a-zA-Z0-9_-]*\.[a-zA-Z][a-zA-Z0-9_-]*$/, // Element.class
        /^[a-zA-Z][a-zA-Z0-9_-]*\#[a-zA-Z][a-zA-Z0-9_-]*$/, // Element#id
        /^\.?[a-zA-Z][a-zA-Z0-9_-]*$/, // .class or class
        /^#[a-zA-Z][a-zA-Z0-9_-]*$/, // #id
        /^[a-zA-Z][a-zA-Z0-9_-]*\[[a-zA-Z][a-zA-Z0-9_-]*\]$/, // Element[attr]
    ];
    
    return allowedPatterns.some(pattern => pattern.test(selector));
}

function sanitizeContent(content) {
    // Remove potentially dangerous content
    return content
        .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '')
        .replace(/<iframe\b[^<]*(?:(?!<\/iframe>)<[^<]*)*<\/iframe>/gi, '')
        .replace(/<object\b[^<]*(?:(?!<\/object>)<[^<]*)*<\/object>/gi, '')
        .replace(/<embed\b[^<]*(?:(?!<\/embed>)<[^<]*)*<\/embed>/gi, '')
        .replace(/javascript:/gi, '')
        .replace(/on\w+\s*=/gi, '');
}